import{_ as a,o as r,c as l,a0 as t}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Read a Player Profile","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/player-profile.md","filePath":"how-to/player-profile.md"}'),i={name:"how-to/player-profile.md"};function o(n,e,s,h,p,c){return r(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="read-a-player-profile" tabindex="-1">Read a Player Profile <a class="header-anchor" href="#read-a-player-profile" aria-label="Permalink to &quot;Read a Player Profile&quot;">​</a></h1><p>The player profile is the deeper view of one player. It combines the current profile, sync state, nickname history, attributes, graphs, and recent records in one place.</p><blockquote><p>Screenshot placeholder: player-profile.png</p></blockquote><h2 id="open-the-profile" tabindex="-1">Open the profile <a class="header-anchor" href="#open-the-profile" aria-label="Permalink to &quot;Open the profile&quot;">​</a></h2><p>Open <strong>Players</strong>, then select the player&#39;s name or profile action.</p><h2 id="main-sections-on-the-page" tabindex="-1">Main sections on the page <a class="header-anchor" href="#main-sections-on-the-page" aria-label="Permalink to &quot;Main sections on the page&quot;">​</a></h2><p>The profile is organized into these sections:</p><ul><li><strong>Profile Foundation</strong></li><li><strong>Sync State</strong></li><li><strong>Nickname History</strong></li><li><strong>Player Attributes</strong></li><li><strong>Graphs</strong></li><li><strong>Resolved Records</strong></li><li><strong>Events</strong></li></ul><h2 id="profile-foundation" tabindex="-1">Profile Foundation <a class="header-anchor" href="#profile-foundation" aria-label="Permalink to &quot;Profile Foundation&quot;">​</a></h2><p>This is the main identity area. Depending on your role, you may be able to edit:</p><ul><li>name</li><li>Kingshot profile ID</li><li>external profile URL</li><li>avatar URL</li><li>power</li><li>level</li><li>game rank</li><li>TC level</li><li>alliance</li><li>alliance role</li><li>alliance status</li><li>notes</li></ul><p>If you change the alliance from one current alliance to another, the page asks you to confirm the transfer so the membership history is recorded correctly.</p><h2 id="sync-state" tabindex="-1">Sync State <a class="header-anchor" href="#sync-state" aria-label="Permalink to &quot;Sync State&quot;">​</a></h2><p>This section tells you whether the player is:</p><ul><li>API linked</li><li>local only</li><li>recently synced</li></ul><p>It also shows the current status labels the player is carrying.</p><h2 id="nickname-history" tabindex="-1">Nickname History <a class="header-anchor" href="#nickname-history" aria-label="Permalink to &quot;Nickname History&quot;">​</a></h2><p>Use this area when imports, manual notes, or old event records use a former player name.</p><p>You can:</p><ul><li>add a nickname</li><li>make an older nickname the current one</li><li>remove a non-current nickname</li></ul><h2 id="player-attributes" tabindex="-1">Player Attributes <a class="header-anchor" href="#player-attributes" aria-label="Permalink to &quot;Player Attributes&quot;">​</a></h2><p>This section shows the player&#39;s current status and any extra attributes from analytics or manual decisions. If your role allows it, you can also add manual attributes and save or clear a manual status override here.</p><h2 id="graphs-and-records" tabindex="-1">Graphs and records <a class="header-anchor" href="#graphs-and-records" aria-label="Permalink to &quot;Graphs and records&quot;">​</a></h2><p>The lower parts of the page help you answer questions like:</p><ul><li>how often this player appears</li><li>how their score changes over time</li><li>what name imported rows used</li><li>which events they have been part of</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./nicknames.html">Manage Nickname History</a></li><li><a href="./manual-attributes.html">Manual Attributes &amp; Status Overrides</a></li><li><a href="./player-sync.html">Sync Players from the Game API</a></li><li><a href="./../reference/alliance-membership.html">How Alliance Membership Works</a></li></ul>',27)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
